const { BigQuery } = require('@google-cloud/bigquery');

const bigquery = new BigQuery();

exports.processBigData = async (req, res) => {
  try {
    const {
      projectId,
      datasetId,
      tableId,
      query,
      destinationTable,
      writeDisposition = 'WRITE_TRUNCATE',
      location
    } = req.body || {};

    if (!projectId) return res.status(400).send('Missing required field: projectId');
    if (!query && (!datasetId || !tableId)) {
      return res.status(400).send('Provide either query or datasetId/tableId');
    }

    const options = {
      location,
      useLegacySql: false
    };

    let sql = query;

    if (!sql) {
      sql = `
        SELECT
          *
        FROM \`${projectId}.${datasetId}.${tableId}\`
      `;
    }

    const [job] = await bigquery.createQueryJob({
      query: sql,
      ...options,
      ...(destinationTable
        ? {
            destination: bigquery.dataset(destinationTable.datasetId).table(destinationTable.tableId),
            writeDisposition
          }
        : {})
    });

    const [rows] = await job.getQueryResults();

    res.status(200).json({
      success: true,
      jobId: job.id,
      rowCount: rows.length,
      rows
    });
  } catch (error) {
    console.error('BigQuery processing failed:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
};